def gen(rng, size):
    m = max(3, min(40, size))
    n = max(3, min(40, size))
    grid = [[rng.randint(0, 50) for _ in range(n)] for _ in range(m)]
    for j in range(n):
        grid[0][j] = 60; grid[m - 1][j] = 60
    for i in range(m):
        grid[i][0] = 60; grid[i][n - 1] = 60
    return [grid]

