class Solution:
    def trapRainWater(self, heightMap):
        m = len(heightMap)
        n = len(heightMap[0]) if m else 0
        if m < 3 or n < 3:
            return 0
        H = max(max(row) for row in heightMap)
        # independent relaxation: start every interior water level at H and repeatedly
        # lower it to the min of neighbour water levels (bounded by own height).
        INF = H
        water = [[INF] * n for _ in range(m)]
        for i in range(m):
            for j in range(n):
                if i == 0 or j == 0 or i == m - 1 or j == n - 1:
                    water[i][j] = heightMap[i][j]
        changed = True
        while changed:
            changed = False
            for i in range(1, m - 1):
                for j in range(1, n - 1):
                    lo = min(water[i-1][j], water[i+1][j], water[i][j-1], water[i][j+1])
                    cand = max(heightMap[i][j], lo)
                    if cand < water[i][j]:
                        water[i][j] = cand
                        changed = True
        return sum(water[i][j] - heightMap[i][j] for i in range(m) for j in range(n))

