import heapq
class Solution:
    def trapRainWater(self, heightMap):
        m = len(heightMap)
        n = len(heightMap[0]) if m else 0
        if m < 3 or n < 3:
            return 0
        visited = [[False] * n for _ in range(m)]
        heap = []
        for i in range(m):
            for j in range(n):
                if i == 0 or j == 0 or i == m - 1 or j == n - 1:
                    visited[i][j] = True
                    heapq.heappush(heap, (heightMap[i][j], i, j))
        total = 0
        while heap:
            h, i, j = heapq.heappop(heap)
            for di, dj in ((1,0),(-1,0),(0,1),(0,-1)):
                ni, nj = i + di, j + dj
                if 0 <= ni < m and 0 <= nj < n and not visited[ni][nj]:
                    visited[ni][nj] = True
                    level = max(h, heightMap[ni][nj])
                    total += level - heightMap[ni][nj]
                    heapq.heappush(heap, (level, ni, nj))
        return total

