var trapRainWater = function(heightMap) {
    const m = heightMap.length;
    const n = m ? heightMap[0].length : 0;
    if (m < 3 || n < 3) return 0;
    const visited = Array.from({length: m}, () => new Array(n).fill(false));
    // simple binary min-heap of [height, i, j]
    const heap = [];
    const push = (item) => {
        heap.push(item);
        let c = heap.length - 1;
        while (c > 0) {
            const p = (c - 1) >> 1;
            if (heap[p][0] <= heap[c][0]) break;
            [heap[p], heap[c]] = [heap[c], heap[p]];
            c = p;
        }
    };
    const pop = () => {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length) {
            heap[0] = last;
            let c = 0;
            const N = heap.length;
            while (true) {
                let l = 2 * c + 1, r = 2 * c + 2, s = c;
                if (l < N && heap[l][0] < heap[s][0]) s = l;
                if (r < N && heap[r][0] < heap[s][0]) s = r;
                if (s === c) break;
                [heap[s], heap[c]] = [heap[c], heap[s]];
                c = s;
            }
        }
        return top;
    };
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (i === 0 || j === 0 || i === m - 1 || j === n - 1) {
                visited[i][j] = true;
                push([heightMap[i][j], i, j]);
            }
        }
    }
    let total = 0;
    const dirs = [[1,0],[-1,0],[0,1],[0,-1]];
    while (heap.length) {
        const [h, i, j] = pop();
        for (const [di, dj] of dirs) {
            const ni = i + di, nj = j + dj;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n && !visited[ni][nj]) {
                visited[ni][nj] = true;
                const level = Math.max(h, heightMap[ni][nj]);
                total += level - heightMap[ni][nj];
                push([level, ni, nj]);
            }
        }
    }
    return total;
};
